sql.where:
AND deleted = 0
AND status = #{status}
AND applicant_dept LIKE '%' + #{dept} + '%'
AND course_id = #{courseId}
AND applicant_username = #{username}
AND applicant_name LIKE '%' + #{name} + '%'
AND course_name LIKE '%' + #{courseName} + '%'

    AND (applicant_name LIKE '%' + #{keyword} + '%' OR course_name LIKE '%' + #{keyword} + '%' OR applicant_dept LIKE '%' + #{keyword} + '%')
